content = open('task/3/EmitIR.cpp').read()

# Revert IfStmt
new_if = '''void
EmitIR::operator()(IfStmt* obj)
{
  auto& irb = *mCurIrb;
  auto cond = self(obj->cond);

  auto thenBb = llvm::BasicBlock::Create(mCtx, "if.then", mCurFunc);
  auto elseBb = obj->else_ ? llvm::BasicBlock::Create(mCtx, "if.else", mCurFunc) : nullptr;
  auto endBb = llvm::BasicBlock::Create(mCtx, "if.end", mCurFunc);

  if (elseBb)
    irb.CreateCondBr(cond, thenBb, elseBb);
  else
    irb.CreateCondBr(cond, thenBb, endBb);

  irb.SetInsertPoint(thenBb);
  self(obj->then);
  if (!irb.GetInsertBlock()->getTerminator())
    irb.CreateBr(endBb);

  if (elseBb) {
    irb.SetInsertPoint(elseBb);
    self(obj->else_);
    if (!irb.GetInsertBlock()->getTerminator())
      irb.CreateBr(endBb);
  }

  if (!endBb->hasNPredecessorsOrMore(1)) {
    irb.SetInsertPoint(endBb);
    return;
  }
  irb.SetInsertPoint(endBb);
}'''

# Find and replace the current IfStmt (has endBb->insertInto)
# Just use sed-like approach
lines = content.split('\n')
in_ifstmt = False
brace_count = 0
if_start = -1
for i, line in enumerate(lines):
    if 'void' in line and 'EmitIR::operator()(IfStmt*' in line:
        if_start = i
        in_ifstmt = True
    if in_ifstmt and '{' in line:
        brace_count += line.count('{')
    if in_ifstmt and '}' in line:
        brace_count -= line.count('}')
        if brace_count == 0 and if_start >= 0:
            if_end = i
            break

print(f"IfStmt: lines {if_start+1} to {if_end+1}")
new_lines = lines[:if_start] + new_if.strip().split('\n') + lines[if_end+1:]

# Revert WhileStmt
content2 = '\n'.join(new_lines)
lines2 = content2.split('\n')
in_while = False
brace_count = 0
while_start = -1
for i, line in enumerate(lines2):
    if 'void' in line and 'EmitIR::operator()(WhileStmt*' in line:
        while_start = i
        in_while = True
    if in_while and '{' in line:
        brace_count += line.count('{')
    if in_while and '}' in line:
        brace_count -= line.count('}')
        if brace_count == 0 and while_start >= 0:
            while_end = i
            break

print(f"WhileStmt: lines {while_start+1} to {while_end+1}")

new_while = '''void
EmitIR::operator()(WhileStmt* obj)
{
  auto& irb = *mCurIrb;

  auto condBb = llvm::BasicBlock::Create(mCtx, "while.cond", mCurFunc);
  auto bodyBb = llvm::BasicBlock::Create(mCtx, "while.body", mCurFunc);
  auto endBb = llvm::BasicBlock::Create(mCtx, "while.end", mCurFunc);

  auto prevLoopCond = mLoopCond;
  auto prevLoopEnd = mLoopEnd;
  mLoopCond = condBb;
  mLoopEnd = endBb;

  irb.CreateBr(condBb);

  irb.SetInsertPoint(condBb);
  auto cond = self(obj->cond);
  irb.CreateCondBr(cond, bodyBb, endBb);

  irb.SetInsertPoint(bodyBb);
  self(obj->body);
  if (!irb.GetInsertBlock()->getTerminator())
    irb.CreateBr(condBb);

  irb.SetInsertPoint(endBb);

  mLoopCond = prevLoopCond;
  mLoopEnd = prevLoopEnd;
}'''

final_lines = lines2[:while_start] + new_while.strip().split('\n') + lines2[while_end+1:]
open('task/3/EmitIR.cpp', 'w').write('\n'.join(final_lines))
print("Reverted IfStmt and WhileStmt")
PYEOF

